#include <iostream>\n#include <vector>\n#include <limits>\n#include <queue>\n\nclass Graph {\n public:\n  explicit Graph(int n) : n_(n) {\n    table_.resize(n_);\n  }\n\n  void AddEdge(int a, int b, int w) {\n    table_[--a].emplace_back(--b, w);\n    table_[b].emplace_back(a, w);\n  }\n\n  int GetPrim() {\n    std::priority_queue<std::pair<int, int>, std::vector<std::pair<int, int>>, PairCompare> q;\n    std::vector<bool> visited(n_, false);\n    int weight = 0;\n    q.emplace(0, 0);\n    while (!q.empty()) {\n      int v = q.top().first;\n      int w = q.top().second;\n      q.pop();\n      if (visited[v]) {\n        continue;\n      }\n      visited[v] = true;\n      weight += w;\n      for (const std::pair<int, int>& p : table_[v]) {\n        int v_child = p.first;\n        int w_child = p.second;\n        if (!visited[v_child]) {\n          q.emplace(v_child, w_child);\n        }\n      }\n    }\n    return weight;\n  }\n\n private:\n  struct PairCompare {\n    bool operator()(const std::pair<int, int>& l, const std::pair<int, int>& r) const {\n      return l.second > r.second;\n    }\n  };\n  static constexpr int kInf = std::numeric_limits<int>::max();\n\n  int n_;\n  std::vector<std::vector<std::pair<int, int>>> table_;\n};\n\nint main() {\n  int n = 0;\n  int m = 0;\n  std::cin >> n >> m;\n  Graph g(n);\n  for (int i = 0; i < m; i++) {\n    int a = 0;\n    int b = 0;\n    int w = 0;\n    std::cin >> a >> b >> w;\n    g.AddEdge(a, b, w);\n  }\n  std::cout << g.GetPrim() << std::endl;\n  return 0;\n}